mapper.sql:
sr.deleted = 0
AND sr.order_type = 2
AND sr.outbound_mode IN ('CUSTOMER', 'GROUP_CUSTOMER')
AND sr.customer_id IS NOT NULL
AND sr.dept_id = #{deptId}

    AND UPPER(sr.dept_code) = UPPER(#{query.groupCode})


    AND EXISTS (
        SELECT 1
        FROM t_customer c
        WHERE c.id = sr.customer_id
          AND c.deleted = 0
          AND c.owner_user_id = #{ownerUserId}
    )

AND sr.customer_id = #{query.customerId}

    AND sr.customer_name LIKE CONCAT('%', #{query.customerName}, '%')

AND sr.goods_id = #{query.goodsId}

    AND sr.goods_name LIKE CONCAT('%', #{query.goodsName}, '%')

AND sr.sku_id = #{query.skuId}

    AND sr.sku_code LIKE CONCAT('%', #{query.skuCode}, '%')

AND sr.stock_type_id = #{query.stockTypeId}
AND sr.biz_date  >=  #{query.startDate}
AND sr.biz_date  <=  #{query.endDate}

o.deleted = 0
AND i.deleted = 0
AND o.order_type = 2
AND o.state = 2
AND o.outbound_mode IN ('CUSTOMER', 'GROUP_CUSTOMER')
AND o.customer_id IS NOT NULL
AND o.dept_id = #{deptId}

    AND UPPER(o.dept_code) = UPPER(#{query.groupCode})


    AND EXISTS (
        SELECT 1
        FROM t_customer c
        WHERE c.id = o.customer_id
          AND c.deleted = 0
          AND c.owner_user_id = #{ownerUserId}
    )

AND o.customer_id = #{query.customerId}

    AND o.customer_name LIKE CONCAT('%', #{query.customerName}, '%')

AND i.category_id = #{query.categoryId}

    AND i.category_name LIKE CONCAT('%', #{query.categoryName}, '%')

AND i.goods_id = #{query.goodsId}

    AND i.goods_name LIKE CONCAT('%', #{query.goodsName}, '%')

AND i.sku_id = #{query.skuId}

    AND i.sku_code LIKE CONCAT('%', #{query.skuCode}, '%')

AND i.stock_type_id = #{query.stockTypeId}

    AND COALESCE(i.biz_date, o.biz_date)  >=  #{query.startDate}


    AND COALESCE(i.biz_date, o.biz_date)  <=  #{query.endDate}

o.deleted = 0
AND i.deleted = 0
AND o.order_type = 2
AND o.state = 2
AND o.outbound_mode IN ('CUSTOMER', 'GROUP_CUSTOMER')
AND o.customer_id IS NOT NULL
AND o.dept_id = #{deptId}

    AND UPPER(o.dept_code) = UPPER(#{query.groupCode})


    AND c.owner_user_id = #{ownerUserId}


    AND COALESCE(NULLIF(TRIM(c.country), ''), '未設定') LIKE CONCAT('%', #{query.country}, '%')

AND o.customer_id = #{query.customerId}

    AND o.customer_name LIKE CONCAT('%', #{query.customerName}, '%')

AND i.category_id = #{query.categoryId}

    AND i.category_name LIKE CONCAT('%', #{query.categoryName}, '%')

AND i.goods_id = #{query.goodsId}

    AND i.goods_name LIKE CONCAT('%', #{query.goodsName}, '%')

AND i.sku_id = #{query.skuId}

    AND i.sku_code LIKE CONCAT('%', #{query.skuCode}, '%')

AND i.stock_type_id = #{query.stockTypeId}

    AND COALESCE(i.biz_date, o.biz_date)  >=  #{query.startDate}


    AND COALESCE(i.biz_date, o.biz_date)  <=  #{query.endDate}

mapper.select:
SELECT i.goods_id AS goodsId, o.customer_id AS customerId, SUM(ABS(i.before_qty - i.after_qty)) AS quantity FROM t_stock_order o INNER JOIN t_stock_order_item i ON i.order_id = o.id WHERE AND i.goods_id IN
#{goodsId}
GROUP BY i.goods_id, o.customer_id

SELECT COALESCE(NULLIF(TRIM(c.country), ''), '未設定') AS country, o.customer_id AS customerId, o.customer_name AS customerName, o.dept_id AS deptId, o.dept_code AS groupCode, o.order_no AS bizNo, o.id AS orderId, i.id AS orderItemId, i.id AS recordId, i.goods_id AS goodsId, i.goods_name AS goodsName, i.sku_id AS skuId, i.sku_code AS skuCode, i.stock_type_id AS stockTypeId, i.stock_type_name AS stockTypeName, ABS(i.before_qty - i.after_qty) AS quantity, COALESCE(i.biz_date, o.biz_date) AS outboundDate, o.operator_id AS operatorId, o.operator_name AS operatorName FROM t_stock_order o INNER JOIN t_stock_order_item i ON i.order_id = o.id LEFT JOIN t_customer c ON c.id = o.customer_id AND c.deleted = 0 WHERE AND COALESCE(NULLIF(TRIM(c.country), ''), '未設定') IN
#{country}
ORDER BY country ASC, o.customer_name ASC, o.customer_id ASC, COALESCE(i.biz_date, o.biz_date) DESC, i.id DESC
